namespace InventoryApp.Models;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using InventoryApp.Models;

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a real data-fetch delay
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Hydraulic Press",      Location = "Building A – Bay 3",   LastInspected = new DateTime(2026, 4, 12) },
            new() { Id = 2, Name = "CNC Lathe",            Location = "Building B – Shop 1",  LastInspected = new DateTime(2026, 3, 28) },
            new() { Id = 3, Name = "Overhead Crane (5-ton)", Location = "Warehouse C",         LastInspected = new DateTime(2026, 5, 1)  },
            new() { Id = 4, Name = "Forklift #7",          Location = "Loading Dock",         LastInspected = new DateTime(2026, 5, 20) },
            new() { Id = 5, Name = "Welding Station",      Location = "Building A – Bay 7",   LastInspected = new DateTime(2026, 2, 15) },
            new() { Id = 6, Name = "Bandsaw",              Location = "Building B – Shop 2",  LastInspected = new DateTime(2025, 12, 10)},
            new() { Id = 7, Name = "Air Compressor",       Location = "Utility Room 1",       LastInspected = new DateTime(2026, 1, 22) },
            new() { Id = 8, Name = "Paint Booth",          Location = "Building D",           LastInspected = new DateTime(2026, 4, 30) },
        };
    }
}

@page "/inventory"
@using InventoryApp.Models
@using InventoryApp.Services
@rendermode InteractiveServer
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistSub;

    private const string PersistKey = "equipmentItems";

    protected override async Task OnInitializedAsync()
    {
        // During interactive activation, try to restore persisted prerender data.
        // If the data was persisted during prerender, we skip the service call entirely.
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>(PersistKey, out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentSvc.GetEquipmentAsync();
        }

        // Register a callback so the prerender pass persists the data for the
        // interactive pass, preventing a second fetch.
        _persistSub = ApplicationState.RegisterOnPersisting(() =>
        {
            ApplicationState.PersistAsJson(PersistKey, _items);
            return Task.CompletedTask;
        });
    }

    public void Dispose()
    {
        _persistSub.Dispose();
    }
}

